#[derive(Debug, Clone, PartialEq)]
enum Role { Admin, User, Guest }

#[derive(Debug, Clone, PartialEq)]
enum Permission { ReadUsers, WriteUsers, DeleteUsers, ManageSystem }

impl Role {
    fn permissions(&self) -> Vec<Permission> {
        match self {
            Role::Admin => vec![Permission::ReadUsers, Permission::WriteUsers, Permission::DeleteUsers, Permission::ManageSystem],
            Role::User => vec![Permission::ReadUsers],
            Role::Guest => vec![],
        }
    }
    fn has_permission(&self, perm: &Permission) -> bool {
        self.permissions().contains(perm)
    }
}

async fn require_permission(user: &AuthUser, perm: Permission) -> Result<(), AppError> {
    if !user.role.has_permission(&perm) {
        tracing::warn!(user_id = %user.id, "unauthorized access attempt");
        return Err(AppError::Forbidden);
    }
    Ok(())
}

