use tower_sessions::{SessionManagerLayer, MemoryStore, Session};

let session_store = MemoryStore::default();
let session_layer = SessionManagerLayer::new(session_store)
    .with_secure(true)
    .with_same_site(tower_sessions::cookie::SameSite::Strict)
    .with_http_only(true)
    .with_max_age(time::Duration::hours(24));

let app = Router::new()
    .route("/login", post(login))
    .layer(session_layer);

async fn login(session: Session, Json(creds): Json<LoginRequest>) -> Result<StatusCode, AppError> {
    let user = authenticate(creds).await?;
    session.insert("user_id", user.id).await?;
    Ok(StatusCode::OK)
}

